【UNR #2】黎明前的巧克力
题目链接
难度：简单
考虑如果一个集合大小为  的集合  中的所有数字异或和为 ，那对答案的贡献应该是 ，前提是 ，如果 ，则贡献应该是 ，我们最后再去掉这个限制的影响。
由此我们可以写出巧克力的结合幂级数：

一个暴力的想法是直接用 ，但是这样一共要做  次 ，每一次都是  的（ 表示值域），对于时间来说非常浪费，我们需要考虑利用这个集合幂级数的特殊性质。
根据我们之前博客讲过的  的式子，容易发现，每一项的数都是  或者是 ，所以我们可以考虑算出来最后的每个位置上有多少个集合幂级数是 ，有多少个是 。具体来说，把上面的集合幂级数累加，然后只做一遍 ，通过解方程，我们可以得到把上面的式子异或卷积之后的到的  式子。然后  即可。
代码：
#include&lt;bits/stdc++.h&gt;
#define mset(a,b) memset((a),(b),sizeof((a)))
#define rep(i,l,r) for(int i=(l);i&lt;=(r);i++)
#define dec(i,l,r) for(int i=(r);i&gt;=(l);i--)
#define inc(a,b) (((a)+(b))&gt;=mod?(a)+(b)-mod:(a)+(b))
#define sub(a,b) (((a)-(b))&lt;0?(a)-(b)+mod:(a)-(b))
#define mul(a,b) 1ll*(a)*(b)%mod
#define sgn(a) (((a)&amp;1)?(mod-1):1)
#define cmax(a,b) (((a)&lt;(b))?(a=b):(a))
#define cmin(a,b) (((a)&gt;(b))?(a=b):(a))
#define Next(k) for(int x=head[k];x;x=li[x].next)
#define vc vector
#define ar array
#define pi pair
#define fi first
#define se second
#define mp make_pair
#define pb push_back
#define N 2000100
#define M number
using namespace std;

typedef double dd;
typedef long double ld;
typedef long long ll;
typedef unsigned int uint;
typedef unsigned long long ull;
//#define int long long
typedef pair&lt;int,int&gt; P;
typedef vector&lt;int&gt; vi;

const int INF=0x3f3f3f3f;
const dd eps=1e-9;
const int mod=998244353;

template&lt;typename T&gt; inline void read(T &amp;x) {
    x=0; int f=1;
    char c=getchar();
    for(;!isdigit(c);c=getchar()) if(c == '-') f=-f;
    for(;isdigit(c);c=getchar()) x=x*10+c-'0';
    x*=f;
}

int n,a[N],b[N],inv2,c[N],inv4;

inline int ksm(int a,int b,int mod){int res=1;while(b){if(b&amp;1)res=1ll*res*a%mod;a=1ll*a*a%mod;b&gt;&gt;=1;}return res;}
inline int inv(int a){return ksm(a,mod-2,mod);}
inline P Calc(int a,int b){
    int x=1ll*((a+b)%mod)*inv4%mod;
    int y=(a-x)%mod;
    // x=(x+mod)%mod;y=(y+mod)%mod;
    return mp(x,y);
}
inline void FWT(int *f,int n,int op){
    for(int i=2;i&lt;=n;i&lt;&lt;=1)
        for(int l=0;l&lt;n;l+=i)
            rep(k,l,l+i/2-1){
                // printf("k=%d\n",k);
                int a=f[k],b=f[k+i/2];
                if(op){
                    f[k]=(a+b)%mod;f[k+i/2]=(a-b)%mod;
                }
                else{
                    f[k]=1ll*((a+b)%mod)*inv2%mod;
                    f[k+i/2]=1ll*((a-b)%mod)*inv2%mod;
                }
            }
}

int main(){
    // assert(freopen("my.in","r",stdin));
    // assert(freopen("my.out","w",stdout));
    inv2=ksm(2,mod-2,mod);inv4=inv(4);
    read(n);rep(i,1,n) read(a[i]);
    int nn=n;
    rep(i,1,n) b[a[i]]+=2;b[0]+=n;
    int m=1000000;n=1;while(n&lt;m) n&lt;&lt;=1;
    FWT(b,n,1);
    // rep(i,0,n-1) printf("%d ",b[i]);puts("");
    rep(i,0,n-1){
        P now=Calc(nn,b[i]);
        // printf("now.fi=%d now.se=%d\n",now.fi,now.se);
        c[i]=1ll*ksm(3,now.fi,mod)*sgn(now.se)%mod;
    }
    FWT(c,n,0);
    c[0]--;
    printf("%d\n",(c[0]+mod)%mod);
    return 0;
}









